-- Tablas de ministerios y órganos gestores
-- Datos estáticos de la administración central del estado

-- Tabla de ministerios
CREATE TABLE IF NOT EXISTS dim.ministerios (
    id SERIAL PRIMARY KEY,
    descripcion VARCHAR(255) NOT NULL UNIQUE
);

-- Tabla de órganos gestores por ministerio
CREATE TABLE IF NOT EXISTS dim.organos_gestores_ministerios (
    id_ministerio INTEGER NOT NULL REFERENCES dim.ministerios(id),
    descripcion VARCHAR(255) NOT NULL
);

-- Crear índice para consultas eficientes por ministerio
CREATE INDEX IF NOT EXISTS idx_organos_ministerio 
ON dim.organos_gestores_ministerios(id_ministerio);

-- Insertar ministerios
ON CONFLICT DO NOTHING;

-- Insertar órganos gestores por ministerio
ON CONFLICT DO NOTHING;
